css_template:
.news-container-v8 {
    position: absolute;
    bottom: 50px;
    width: var(--v-width, 100%);
    height: var(--v-height, 60px);
    background: {{PRIMARY_BG}};
    color: {{TITLE_COLOR}};
    display: flex;
    align-items: center;
    overflow: hidden;
    border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}};
    border-radius: {{BORDER_RADIUS}}px;
    box-sizing: border-box;
    font-family: {{FONT_FAMILY}}, sans-serif;
    opacity: 0;
    transform: translateY(100px);
    z-index: 50;
}
.news-text-v8 {
    position: absolute;
    width: auto;
    left: 0;
    white-space: nowrap;
    text-align: left;
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    padding-left: 170px;
    padding-right: 20px;
    box-sizing: border-box;
    z-index: 1;
    transition: opacity 0.4s ease-in-out;
    opacity: 0;
}
.news-text-v8.visible {
    opacity: 1;
}
.wiper-v8 {
    position: absolute;
    left: 0;
    width: 150px;
    height: 100%;
    background: {{WIPER_BG}};
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5);
    border-radius: {{BORDER_RADIUS}}px;
    z-index: 2;
    box-sizing: border-box;
}
.wiper-v8::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    border-top: 2px solid rgba(255,255,255,0.8);
    border-bottom: 2px solid rgba(255,255,255,0.8);
    border-radius: {{BORDER_RADIUS}}px;
    pointer-events: none;
    animation: pulse-gleam-v8 1.5s infinite alternate ease-in-out;
}
.wiper-text-v8 {
    font-weight: 900;
    font-size: {{WIPER_FONT_SIZE}}px;
    font-family: {{WIPER_FONT}}, sans-serif;
    color: {{WIPER_TEXT_COLOR}};
    letter-spacing: 1px;
}
.wiper-v8.move-right {
    animation: slide-right-v8 1s linear forwards;
}
.wiper-v8.snap-back {
    animation: slide-back-v8 0.5s ease-in-out forwards;
}
@keyframes slide-right-v8 {
    0% { left: 0%; }
    100% { left: calc(100% - 150px); }
}
@keyframes slide-back-v8 {
    0% { left: calc(100% - 150px); }
    100% { left: 0%; }
}
@keyframes pulse-gleam-v8 {
    0% { opacity: 0.2; }
    100% { opacity: 1; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector('.news-container-v8');
    const textElement = root.querySelector('.news-text-v8');
    const wiper = root.querySelector('.wiper-v8');
    const dataEl = root.querySelector('#f-news-list');
    if(!textElement || !container || !wiper || !dataEl) return;

    let newsList = [];
    try { 
        newsList = JSON.parse(dataEl.innerHTML || "[]"); 
    } catch(e) { 
        newsList = ["BRAK DANYCH"]; 
    }
    if(newsList.length === 0) newsList = ["BRAK WIADOMOŚCI"];

    let currentIndex = 0;
    let activeTimeouts = [];
    let cycleRunning = false;

    function adjustFontSize() {
        const baseFontSize = 40;
        const leftPadding = 170; 
        const maxWidth = container.offsetWidth - (leftPadding + 20);
        textElement.style.fontSize = baseFontSize + "px";
        let currentWidth = textElement.scrollWidth - leftPadding;
        if (currentWidth > maxWidth && currentWidth > 0) {
            const newSize = (maxWidth / currentWidth) * baseFontSize;
            textElement.style.fontSize = newSize + "px";
        }
    }

    function runCycle() {
        if (!cycleRunning) return;
        textElement.classList.remove('visible');
        textElement.innerText = newsList[currentIndex];
        adjustFontSize();

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.add('visible');
        }, 100));

        activeTimeouts.push(setTimeout(() => {
            if(!cycleRunning) return;
            textElement.classList.remove('visible');
            activeTimeouts.push(setTimeout(() => {
                if(!cycleRunning) return;
                wiper.className = 'wiper-v8 move-right';
                activeTimeouts.push(setTimeout(() => {
                    if(!cycleRunning) return;
                    wiper.className = 'wiper-v8 snap-back';
                    activeTimeouts.push(setTimeout(() => {
                        if(!cycleRunning) return;
                        currentIndex = (currentIndex + 1) % newsList.length;
                        runCycle();
                    }, 500));
                }, 1000));
            }, 400));
        }, 4000));
    }

    root.__slt_show = () => {
        cycleRunning = true;
        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" });
        tl.add(() => {
            runCycle();
        }, "+ =0.1");
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        activeTimeouts.forEach(t => clearTimeout(t));
        activeTimeouts = [];
        const tl = gsap.timeline();
        tl.to(container, { opacity: 0, y: 100, duration: 0.4, ease: "power2.in" });
        return tl;
    };

    window.addEventListener('resize', adjustFontSize);
})();
